async run(ctx) {
  if (!process.send && !isTest) {
    console.warn('`nuxi _dev` is an internal command and should not be used directly. Please use `nuxi dev` instead.')
  }

  const cwd = resolve(ctx.args.cwd || ctx.args.rootDir)

  const { initialize } = await import('../dev')
  await initialize({ cwd, args: ctx.args }, ctx)
}

check(): SchemeCheck {
  const response = { valid: false }

  if (!super.check().valid) {
    return response
  }

  if (this.options.cookie.name) {
    const cookies = this.$auth.$storage.getCookies()
    response.valid = Boolean(cookies[this.options.cookie.name])
    return response
  }

  response.valid = true
  return response
}

protected updateTokens(response: HTTPResponse): void {
  const token = getProp(response.data, this.options.token.property) as string
  const refreshToken = getProp(
    response.data,
    this.options.refreshToken.property
  ) as string

  this.token.set(token)

  if (refreshToken) {
    this.refreshToken.set(refreshToken)
  }
}

export async function writeNuxtManifest(nuxt: Nuxt, manifest = resolveNuxtManifest(nuxt)): Promise<NuxtProjectManifest> {
  const manifestPath = resolve(nuxt.options.buildDir, 'nuxt.json')
  await fsp.mkdir(dirname(manifestPath), { recursive: true })
  await fsp.writeFile(manifestPath, JSON.stringify(manifest, null, 2), 'utf-8')
  return manifest
}

export function checkNuxtCompatibility(
  module: NuxtModule,
  nuxtVersion: string,
): boolean {
  if (!module.compatibility?.nuxt) {
    return true
  }

  return satisfies(nuxtVersion, module.compatibility.nuxt, {
    includePrerelease: true,
  })
}

constructor(
  $auth: Auth,
  options: SchemePartialOptions<RefreshSchemeOptions>
) {
  super($auth, options, DEFAULTS)

  // Initialize Refresh Token instance
  this.refreshToken = new RefreshToken(this, this.$auth.$storage)

  // Initialize Refresh Controller
  this.refreshController = new RefreshController(this)
}

async () => {
  // Remove preview token from cookie and session storage
  useCookie('previewToken').value = ''
  window.sessionStorage.removeItem('previewToken')
  window.sessionStorage.removeItem('previewAPI')

  // Remove query params in url to refresh page
  await router.replace({ query: { preview: undefined } })

  // Reload page to fully exit preview mode
  window.location.reload()
}

export function generateRecordUpdate(collection: CollectionInfo, stem: string, data: Record<string, unknown>) {
  const deleteQuery = generateRecordDeletion(collection, stem)

  const insertQuery = generateCollectionInsert(collection, data)

  return `${deleteQuery}; ${insertQuery}`
}

async (event) => {
  const session = await getUserSession(event)

  // If session is not empty, call fetch hook
  if (Object.keys(session).length > 0) {
    await sessionHooks.callHookParallel('fetch', session, event)
  }

  const { secure, ...data } = session

  return data
}

export function handleInvalidState(event: H3Event, provider: OAuthProvider, onError?: OnError) {
  const message = `${upperFirst(provider)} login failed: state mismatch`

  const error = createError({
    statusCode: 500,
    message,
  })

  if (!onError) throw error
  return onError(event, error)
}

export async function clearUserSession(event: H3Event, config?: Partial<SessionConfig>): Promise<boolean> {
  const session = await _useSession(event, config)

  await sessionHooks.callHookParallel('clear', session.data, event)
  await session.clear()

  return true
}

setSchemeEndpoints() {
  const configurationDocument = this.get()

  this.scheme.options.endpoints = defu(this.scheme.options.endpoints, {
    authorization: configurationDocument.authorization_endpoint,
    token: configurationDocument.token_endpoint,
    userInfo: configurationDocument.userinfo_endpoint,
    logout: configurationDocument.end_session_endpoint
  }) as OpenIDConnectSchemeEndpoints
}

getState(key: string): unknown {
  if (!this._getStateWarnShown) {
    this._getStateWarnShown = true
    // eslint-disable-next-line no-console
    console.warn(
      '[AUTH] $auth.getState is deprecated. Please use $auth.$storage.getState() or top level props like $auth.loggedIn'
    )
  }

  return this.$storage.getState(key)
}

get state(): any {
  if (!this._stateWarnShown) {
    this._stateWarnShown = true
    // eslint-disable-next-line no-console
    console.warn(
      '[AUTH] $auth.state is deprecated. Please use $auth.$state or top level props like $auth.loggedIn'
    )
  }

  return this.$state
}

export async function magicastGuard(fn: (() => Promise<string>), message = '') {
  let generated: string | undefined

  try {
    generated = await fn()
  }
  catch (e) {
    logger.error(e)
    throw new Error(`[Nuxt DevTools] Magicast failed to modify Nuxt config automatically. Maybe the config are composed too dynamically that we failed to statically analyze it. ${message}`)
  }

  return generated
}

const close = (id: symbol, value?: any): void => {
  const overlay = getOverlay(id)

  overlay.isOpen = false

  // Resolve the promise if it exists
  if (overlay.resolvePromise) {
    overlay.resolvePromise(value)
    overlay.resolvePromise = undefined
  }
}

async function getNitropackRuntime(): Promise<NitroRuntimeConfigModule | null> {
  if (cachedNitropackRuntime !== undefined) return cachedNitropackRuntime
  const mod = await importOrNull(nitropackRuntimeSpecifier())
  cachedNitropackRuntime = isRuntimeConfigModule(mod) ? mod : null
  return cachedNitropackRuntime
}

async function getNitropackInternalRuntimeConfig(): Promise<NitroRuntimeConfigModule | null> {
  if (cachedNitropackInternalConfig !== undefined) return cachedNitropackInternalConfig
  const mod = await importOrNull(nitropackInternalRuntimeConfigSpecifier())
  cachedNitropackInternalConfig = isRuntimeConfigModule(mod) ? mod : null
  return cachedNitropackInternalConfig
}
